            's.stat_card.1': '<div class="stat-number" style="font-size:1.6rem;">30 min</div> <div class="stat-label" data-i18n="s.hero.c1">movement/day</div>',
            's.stat_card.2': '<div class="stat-number" style="font-size:1.6rem;">BGN 7</div> <div class="stat-label" data-i18n="s.hero.c2">meal/day</div>',
