            's.tracker_item.6': '<input data-habit="no-junk" type="checkbox"/> <span class="tracker-label" data-i18n="s.habit.no_junk">🚫 No junk food</span> ',
            's.shopping_list.1': '<li><span class="item-name">🥚 Eggs</span><span class="item-price">30 pcs</span></li> <li><span class="item-name">🌾 Oats</span><span class="item-price">500g</span></li> <li><span class="item-name">🍚 Rice</span><span class="item-price">1 kg</span></li> <li><span class="item-name">🫘 Lentils</span><span class="item-price">500g</span></li> <li><span class="item-name">🥛 Yogurt</span><span class="item-price">7 pcs</span></li> <li><span class="item-name">🍗 Chicken</span><span class="item-price">1.5-2 kg</span></li> <li><span class="item-name">🍌 Bananas</span><span class="item-price">7 pcs</span></li>',
            's.week_chart.1': '<div class="week-bar"><div class="bar"></div><div class="day-label" data-i18n="s.day.mon">Mon</div></div> <div class="week-bar"><div class="bar"></div><div class="day-label" data-i18n="s.day.tue">Tu</div></div> <div class="week-bar"><div class="bar"></div><div class="day-label" data-i18n="s.day.wed">Wed</div></div> <div class="week-bar"><div class="bar"></div><div class="day-label" data-i18n="s.day.thu">Thu</div></div> <div class="week-bar"><div class="bar"></div><div class="day-label" data-i18n="s.day.fri">Fri</div></div> <div class="week-bar"><div class="bar"></div><div class="day-label" data-i18n="s.day.sat">Sat</div></div> <div class="week-bar"><div class="bar"></div><div class="day-label" data-i18n="s.day.sun">Sun</div></div>',
            's.cta_section.1': '<h2 data-i18n-html="s.cta.h2">Not since Monday.<br/><em class="purple">Today.</em></h2> <p style="color:#888; max-width:480px; margin:0 auto 32px;">You have the knowledge. You have the plan. You have the numbers.<br/>The only thing missing is <strong>the solution</strong>.     </p> <a class="btn btn-purple" href="#" onclick="document.querySelector(\'.accordion-item.purple .accordion-header\').click(); window.scrollTo({top: document.querySelector(\'.accordion-item.purple\').offsetTop - 80, behavior:\'smooth\'}); return false;"> <span data-i18n="s.cta.btn">Start Day 1 →</span> </a> ',
